mapper.select:
select count (*)
from(
   SELECT a.*, ar.*
   FROM ALARM a
            JOIN ALARM_RECEIVE ar
            ON ar.ALM_ID = a.ALM_ID
   where ar.EMP_ID=#{empId}
     and ar.ALM_DEL_YN='N'
     and ar.ALM_YN='N'
   )

mapper.update:
UPDATE ALARM_RECEIVE
SET ALM_YN='Y' , ALM_YN_TM=sysdate
WHERE ALM_RCVR_NO=#{almRcvrNo}

UPDATE ALARM_RECEIVE
SET ALM_DEL_YN='Y'
WHERE ALM_RCVR_NO=#{almRcvrNo}
